INSERT INTO `v1_48f152cac8adc0ccaef4d79f469e5f9bb09c060e2c8584c993943c5f10d400d2` VALUES (0, 506013, 11, 103731, 8, "クリスティーナ！\nあなたはいったいどの面下げて\n私たちの前に……", 0, 0, 0.5, 506, 1);
INSERT INTO `v1_48f152cac8adc0ccaef4d79f469e5f9bb09c060e2c8584c993943c5f10d400d2` VALUES ("", 506014, 3, 103731, 1, "nop_06_tomo_talk_anger", "", 0.2, "", 506, "");
