INSERT INTO `v1_48f152cac8adc0ccaef4d79f469e5f9bb09c060e2c8584c993943c5f10d400d2` VALUES (0, 506018, 11, 104731, 8, "まあまあ、\nトモちゃんもクリスちゃんも。\nせっかくの新年会なんだから……", 0, 0, 0.5, 506, 1);
